154: func (c *Controller) sync(name string) error {
155: 	c.lock.Lock()
156: 	defer c.lock.Unlock()
157: 
158: 	crd, err := c.crdLister.Get(name)
159: 	if err != nil && !errors.IsNotFound(err) {
160: 		return err
161: 	}
162: 
163: 	if errors.IsNotFound(err) || !apiextensionshelpers.IsCRDConditionTrue(crd, apiextensionsv1.Established) {
164: 		c.deleteCRD(name)
165: 		return nil
166: 	}
167: 
168: 	for _, v := range crd.Spec.Versions {
169: 		if !v.Served {
170: 			continue
171: 		}
172: 		c.buildV3Spec(crd, name, v.Name)
173: 	}
174: 
175: 	return nil
176: }
